/**
 * Supabase admin client for server-side database operations.
 * Uses the service role key to bypass RLS and perform direct queries.
 * This replaces Prisma ORM to avoid the table name mapping issue.
 *
 * The `Database` type is the authoritative shape generated by the Supabase
 * CLI from the live DB schema (`generate_typescript_types`). Regenerate it
 * after any migration: `supabase gen types typescript --project-id ...`.
 */
import { createClient, type SupabaseClient } from '@supabase/supabase-js';

