// ─── Compatibility aliases for the previous hand-rolled interfaces ────────────
// Existing call sites import these names directly; derive them from the
// generated Database type so they stay in sync with migrations.

type PublicRow<T extends keyof Database['public']['Tables']> =
  Database['public']['Tables'][T]['Row'];

export type DbUser = PublicRow<'users'>;
export type DbOrganization = PublicRow<'organizations'>;
export type DbOrganizationMember = PublicRow<'organization_members'>;
export type DbProject = PublicRow<'projects'>;
export type DbIntakeMessage = PublicRow<'intake_messages'>;
export type DbSpec = PublicRow<'specs'>;
export type DbArchitecture = PublicRow<'architectures'>;
export type DbBOM = PublicRow<'boms'>;
export type DbBOMRow = PublicRow<'bom_rows'>;
export type DbQuote = PublicRow<'quotes'>;
export type DbIngestionManifest = PublicRow<'ingestion_manifests'>;
export type DbDesignArtifact = PublicRow<'design_artifacts'>;
export type DbDesignJob = PublicRow<'design_jobs'>;
export type DbHandoffRequest = PublicRow<'handoff_requests'>;
export type DbAuditEntry = PublicRow<'audit_entries'>;

// ─── Client singleton ─────────────────────────────────────────────────────────

let _adminClient: SupabaseClient<Database> | null = null;

export function getSupabaseAdmin(): SupabaseClient<Database> {
  if (_adminClient) return _adminClient;

  const url = process.env.NEXT_PUBLIC_SUPABASE_URL;
  const key = process.env.SUPABASE_SERVICE_ROLE_KEY;

  if (!url || !key) {
    throw new Error('Missing NEXT_PUBLIC_SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY');
  }

  _adminClient = createClient<Database>(url, key, {
    auth: {
      autoRefreshToken: false,
      persistSession: false,
    },
  });

  return _adminClient;
}
